VALUES
  ('dietitian-moex-07154', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '我國健康食品之安全性評估中，若產品之原料非屬傳統食用且含有致癌物之類似物者歸屬於第四類安全 性評估，下列何者不是其應檢具的毒性測試資料？ 基因毒性試驗  28天餵食毒性試驗  繁殖試驗  致癌性試驗', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07155', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '根據行政院衛生署（現為衛生福利部）在民國96年所頒布之「食品用洗潔劑衛生標準」，下列敘述何者 正確？ 本標準所稱之食品用洗潔劑不適用固態肥皂、供餐具自動洗淨機使用之洗潔劑、酸液、鹼液及 漂白水等 食品用洗潔劑不得檢出任何壬基苯酚類（nonylphenol及nonylphenol ethoxylate）介面活性劑 食品用洗潔劑之螢光增白劑含量須在0.1%以下 食品用洗潔劑不得添加任何香料及著色劑', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07156', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '俗稱寶特瓶的製造原料為： 聚丙烯（polypropylene, PP） 聚氯乙烯（polyvinylchloride, PVC） 聚碳酸酯（polycarbonate, PC） 聚乙烯對苯二甲酸樹脂（polyethylene terephthalate, PET）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07157', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關己二烯酸（sorbic acid）之性質，下列敘述何者正確？ 為飽和酸    抑制真菌能力較細菌高 抑菌能力不受其分子構型影響  抑菌能力不受pH值影響', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07158', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關阿斯巴甜（aspartame）的敘述，下列何者錯誤？ 適合糖尿病患者食用，不會造成血糖上升 為天門冬胺酸（asparagine）及苯丙胺酸（phenylalanine）雙胜肽的酯類化合物 添加於食品中時僅需標示為甜味劑 甜度約為蔗糖的150～200倍，但每公克可產生4大卡之熱量', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07159', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '熱硬化性樹脂（thermosetting resin）如加熱硬化程度不足，則可能有下列何種物質溶出的問題？ 苯乙烯  甲醛  氯乙烯  乙醛', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07160', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據「罐頭食品類衛生標準」規定，金屬罐裝之罐頭食品，其重金屬最大容許量是規範下列那兩種 重金屬？ 鉛、鎘  鐵、錫  鉛、錫  銻、錫', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07161', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關DBP及DEHP塑化劑之敘述，下列何者錯誤？ 屬於鄰苯二甲酸酯類化合物 因共價鍵之破壞從塑膠容器主體結構中釋放出來 塑膠容器盛裝高油脂食品較易溶出 為環境荷爾蒙', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07162', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是屬於動物性天然毒素？ saxitoxin  brevetoxin  patulin  domoic acid', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07163', 'dietitian', 'dietitian-moex-103-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關腹瀉性貝毒（diarrhetic shellfish poisoning, DSP）中毒，下列敘述何者正確？ 毒素不耐熱，易受烹調溫度所破壞 毒素致死率高 食用有毒貝類後，會產生麻痺、呼吸衰竭等症狀 主要是食用受渦鞭毛藻等所污染的二枚貝所導致的中毒', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "8e1a7e5d1d0b", "answer_pdf_sha1": "6a5bc151846b", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
